    /** Get interpretation for a card in a given planetary context. */
    fun get(planet: String, cardCode: String): String {
        val map = when (planet.uppercase()) {
            "BIRTHCARD" -> BIRTHCARD_DATA
            "CROWN"     -> CROWN_DATA
            "MERCURY"   -> MERCURY_DATA
            "VENUS"     -> VENUS_DATA
            "MARS"      -> MARS_DATA
            "JUPITER"   -> JUPITER_DATA
            "SATURN"    -> SATURN_DATA
            "SUN"       -> SUN_DATA
            "MOON"      -> MOON_DATA
            else        -> emptyMap()
        }
        return map[cardCode] ?: map[cardCode.uppercase()] ?: ""
    }

    /** Get position description text for special spread labels. */
    fun getLabel(label: String): String = SPREAD_LABELS[label] ?: ""
}